## Refactored Version

```javascript
const CACHE_TTL_MS = 5 * 60 * 1000;
const pendingRequests = {};

async function getPrice(productId) {
  // Check cache with expiration
  const cached = localStorage.getItem(`price_${productId}`);
  if (cached) {
    try {
      const { price, timestamp } = JSON.parse(cached);
      if (Date.now() - timestamp < CACHE_TTL_MS) {
        return price;
      }
    } catch {
      // Invalid cache data, proceed to fetch
    }
  }

  // Deduplicate concurrent requests
  if (pendingRequests[productId]) {
    return pendingRequests[productId];
  }

  pendingRequests[productId] = fetch(`/api/price/${productId}`)
    .then(res => {
      if (!res.ok) throw new Error(`Failed to fetch price: ${res.status}`);
      return res.json();
    })
    .then(data => {
      const price = data.price ?? data; // handle { price: X } or direct X
      localStorage.setItem(`price_${productId}`, JSON.stringify({
        price,
        timestamp: Date.now()
      }));
      return price;
    })
    .finally(() => {
      delete pendingRequests[productId];
    });

  return pendingRequests[productId];
}
```
